      ajaran: [
        { j: "Hanif — lurus tanpa sekutu", i: "Tauhid Ibrahim bukan warisan melainkan hasil pencarian: menguji segala yang tampak berkuasa sampai semuanya gugur karena 'tenggelam'. Yang tersisa hanyalah Yang tak pernah tenggelam — dan kepada-Nya ia menghadapkan wajah secara hanif (QS 6:79)." },
        { j: "Penyerahan yang diuji, bukan diucapkan", i: "Setiap klaim cintanya ditagih: harta (tamu-tamu dijamu tanpa tanya), tanah air (ditinggalkan), anak (diserahkan). Islamnya bukan kartu identitas melainkan rangkaian penyembelihan kelekatan." },
        { j: "Keramahan sebagai ibadah", i: "Digelari bapak para tamu: tak makan sendirian, menyembelih anak sapi gemuk untuk tamu tak dikenal (QS 51:24–27). Pintu rumah yang terbuka adalah pintu langit yang terbuka." },
        { j: "Doa lintas generasi", i: "Doa-doanya berpikir ribuan tahun ke depan: untuk anak-cucu, untuk negeri yang aman, untuk rasul yang akan datang. Ia mengajarkan bahwa orang beriman menanam pohon yang buahnya dipetik generasi yang belum lahir." },
      ],
      kalimat: [
        { t: "La uhibbul afilin — aku tidak menyukai yang tenggelam.", k: "QS 6:76 — diucapkan saat bintang terbenam; menjadi pisau uji bagi setiap sandaran: apa pun yang bisa hilang, bukan Tuhan." },
        { t: "Inni dzahibun ila Rabbi, sayahdin — sesungguhnya aku pergi menuju Tuhanku; Dia akan menunjukiku.", k: "QS 37:99 — kalimat hijrah: berangkat dulu, petunjuk menyusul di jalan. Motto setiap salik yang memulai tanpa tahu ujung." },
        { t: "Aslamtu li Rabbil-'alamin — aku berserah kepada Tuhan semesta alam.", k: "QS 2:131 — jawaban seketika atas perintah 'aslim'; dari akar kata inilah 'islam' sebagai sikap bermula." },
        { t: "Rabbi arini kayfa tuhyil-mawta… liyathma'inna qalbi — Tuhanku, perlihatkan bagaimana Engkau menghidupkan yang mati… agar hatiku tenteram.", k: "QS 2:260 — piagam para perindu penyaksian: iman-kabar tidak dimarahi ketika meminta naik menjadi iman-penyaksian." },
      ],
      warisan: "Tiga agama besar dunia mengaku kepadanya — karena itu disebut millah Ibrahim, arus induk sebelum bercabang. Dalam Islam warisannya hadir setiap hari: namanya disebut setiap tasyahud dalam shalawat Ibrahimiyah, jejak keluarganya diulang jutaan jamaah setiap haji (sa'i mengulang lari Hajar, kurban mengulang penyembelihannya, maqam Ibrahim menandai tempat berdirinya), dan doanya di lembah Bakkah terjawab menjadi kota yang tak pernah sepi dari thawaf. Bagi kaum arif ia adalah arketipe pencari: bukti bahwa iman hasil memeriksa sendiri lebih kokoh dari iman warisan — dan bahwa Allah tidak menolak orang yang bertanya, asal bertanyanya untuk menyembah, bukan untuk lari.",
